module calendar(
    input CLK,
    input RST,
    output [5:0] Hours,
    output [5:0] Mins,
    output [5:0] Secs
);

reg [5:0] sec_reg, min_reg, hour_reg;
reg [5:0] sec_next, min_next, hour_next;

always @(posedge CLK or posedge RST) begin
    if (RST) begin
        sec_reg <= 6'd0;
        min_reg <= 6'd0;
        hour_reg <= 6'd0;
    end
    else begin
        sec_reg <= sec_next;
        min_reg <= min_next;
        hour_reg <= hour_next;
    end
end

always @* begin
    sec_next = sec_reg + 6'd1;
    min_next = min_reg;
    hour_next = hour_reg;

    if (sec_reg == 6'd59) begin
        sec_next = 6'd0;
        min_next = min_reg + 6'd1;
    end

    if (min_reg == 6'd59 && sec_reg == 6'd59) begin
        min_next = 6'd0;
        hour_next = hour_reg + 6'd1;
    end

    if (hour_reg == 6'd23 && min_reg == 6'd59 && sec_reg == 6'd59) begin
        hour_next = 6'd0;
    end
end

assign Secs = sec_reg;
assign Mins = min_reg;
assign Hours = hour_reg;

endmodule
